import React from "react";

export function BlogHero({ slug, title }) {
  const imagePath = `/blog/image/${slug}.svg`;

  return (
    <figure
      style={{
        margin: "0 0 2rem 0",
        borderRadius: "24px",
        overflow: "hidden",
        border: "1px solid rgba(255,255,255,0.15)",
        boxShadow: "0 20px 60px rgba(10, 20, 30, 0.25)",
      }}
    >
      <img
        src={imagePath}
        alt={title}
        style={{ width: "100%", display: "block", objectFit: "cover" }}
        loading="lazy"
      />
    </figure>
  );
}

