import React from "react";
import { useArticleMeta } from "../../src/lib/useArticleMeta";
import { articleBaseStyles, articleContainerStyles, articleHeadingStyles } from "../../src/lib/articleStyles";
import { BlogHero } from "../../src/lib/blogHero";

const SLUG = "mootori-vibratsioon-tuhikaigul";
const META_TITLE = "Mootori vibratsioon tühikäigul – padjad, süüde või midagi hullemat?";
const META_DESCRIPTION =
  "Analüüsime, miks mootor tühikäigul vibreerib: kas süütesüsteem, mootori padjad, pihustid või juba sügavam mehaaniline probleem.";

const META_TAGS = [
  { name: "description", content: META_DESCRIPTION },
  { property: "og:type", content: "article" },
  { property: "og:title", content: META_TITLE },
  { property: "og:description", content: META_DESCRIPTION },
  { property: "og:url", content: `https://sinu-domeen.ee/blogi/${SLUG}` },
];

const STRUCTURED_DATA = {
  "@context": "https://schema.org",
  "@type": "BlogPosting",
  headline: META_TITLE,
  description: META_DESCRIPTION,
  author: { "@type": "Person", name: "LEISSON" },
  genre: "Automotive",
  keywords: "mootori vibratsioon, tühikäik, mootori padjad",
  articleSection: "Autohooldus",
  mainEntityOfPage: {
    "@type": "WebPage",
    "@id": `https://sinu-domeen.ee/blogi/${SLUG}`,
  },
};

const Heading = ({ as: Tag, children }) => (
  <Tag style={Tag === "h1" ? articleHeadingStyles.h1 : articleHeadingStyles.h2}>{children}</Tag>
);

export default function BlogMootoriVibratsioonTuhikaigul() {
  useArticleMeta({
    title: META_TITLE,
    description: META_DESCRIPTION,
    metaTags: META_TAGS,
    structuredData: STRUCTURED_DATA,
    schemaId: "schema-mootori-vibratsioon-tuhikaigul",
  });

  return (
    <div style={articleBaseStyles}>
      <main style={articleContainerStyles}>
        <article>
          <BlogHero slug={SLUG} title={META_TITLE} />
          <Heading as="h1">Mootori vibratsioon tühikäigul – padjad, süüde või midagi hullemat?</Heading>

          <p>
            Tühikäigul värisev auto on tüüpiline vanema sõiduki sümptom. Vibratsioon räägib ette, kas on tegu lihtsa padjavahetuse, süütesüsteemi veaga või juba sügavama mootoriprobleemiga.
          </p>

          <Heading as="h2">Kas mootor töötab kõigil silindritel?</Heading>
          <p>
            Esimene kontroll on alati <strong>põlemise ühtlus</strong>: kui üks silinder „mängib“, on tunda rütmilist kõikumist, jõnksu kiirendusel ja tihti süttib ka <strong>check engine</strong> (misfire veakoodid).
          </p>

          <Heading as="h2">Mootori padjad – vibratsioon vs mehaaniline kolks</Heading>
          <p>
            Kulunud <strong>mootori kinnituspadjad</strong> lasevad mootoril tühikäigul rohkem kere külge istuda, käiguga sisse-välja lülitades tekib kolks ja kiirendusel või pidurdamisel võib mootor nihkuda.
          </p>

          <Heading as="h2">Diisli ja bensiinimootori erinevus</Heading>
          <p>
            Diisel vibreerib loomupäraselt rohkem, kuid kui vibratsioon on oluliselt suurem kui varem, tunda tugevalt roolis ja kaasnevad helid, siis ei ole tegu „iseloomuga“.
          </p>

          <Heading as="h2">Pihustid ja kütusesegu</Heading>
          <p>
            Mustad või lekkivad <strong>pihustid</strong> tekitavad ebavõrdset kütusekogust silindrite vahel, mis põhjustab ebastabiilset põlemist tühikäigul.
          </p>

          <Heading as="h2">Mehaaniline kulumine</Heading>
          <p>
            Väga suure läbisõiduga mootoritel võivad erinev kompressioon või saalede kulumine põhjustada vibratsiooni, mis ei kao ka pärast süütesüsteemi ja pihustite korrastamist.
          </p>

          <Heading as="h2">Kuidas diagnoosida?</Heading>
          <ol>
            <li>Lugetakse välja <strong>veakoodid</strong>.</li>
            <li>Tehakse <strong>visuaalne kontroll</strong> – padjad, voolikud, lekked.</li>
            <li>Vajadusel mõõdetakse <strong>kompressioon</strong> ja kontrollitakse pihusteid.</li>
          </ol>

          <Heading as="h2">Kokkuvõte</Heading>
          <p>
            <strong>Mootori vibratsioon tühikäigul</strong> võib olla nii lihtne padjavahetus kui ka tõsise mehaanilise kulumise märk. Kui vibratsioon on uus või tugevneb, tasub lasta mootor süsteemselt üle vaadata.
          </p>
        </article>
      </main>
    </div>
  );
}
