import React from "react";
import { useArticleMeta } from "../../src/lib/useArticleMeta";
import { articleBaseStyles, articleContainerStyles, articleHeadingStyles } from "../../src/lib/articleStyles";
import { BlogHero } from "../../src/lib/blogHero";

const SLUG = "turbolaaduri-eluiga-pikendavad-hooldused";
const META_TITLE = "Turbolaaduri eluiga pikendavad hooldused – mida vanematel autodel arvestada?";
const META_DESCRIPTION =
  "Kuidas pikendada turbolaaduri eluiga vanemal autol: õlivahetus, jahutus, sõiduvõtted, lekete ja rõhu kontroll.";

const META_TAGS = [
  { name: "description", content: META_DESCRIPTION },
  { property: "og:type", content: "article" },
  { property: "og:title", content: META_TITLE },
  { property: "og:description", content: META_DESCRIPTION },
  { property: "og:url", content: `https://sinu-domeen.ee/blogi/${SLUG}` },
];

const STRUCTURED_DATA = {
  "@context": "https://schema.org",
  "@type": "BlogPosting",
  headline: META_TITLE,
  description: META_DESCRIPTION,
  author: { "@type": "Person", name: "LEISSON" },
  genre: "Automotive",
  keywords: "turbolaadur, turbo hooldus, õlivahetus",
  articleSection: "Autohooldus",
  mainEntityOfPage: {
    "@type": "WebPage",
    "@id": `https://sinu-domeen.ee/blogi/${SLUG}`,
  },
};

const Heading = ({ as: Tag, children }) => (
  <Tag style={Tag === "h1" ? articleHeadingStyles.h1 : articleHeadingStyles.h2}>{children}</Tag>
);

export default function BlogTurbolaaduriEluigaPikendavadHooldused() {
  useArticleMeta({
    title: META_TITLE,
    description: META_DESCRIPTION,
    metaTags: META_TAGS,
    structuredData: STRUCTURED_DATA,
    schemaId: "schema-turbolaaduri-eluiga-pikendavad-hooldused",
  });

  return (
    <div style={articleBaseStyles}>
      <main style={articleContainerStyles}>
        <article>
          <BlogHero slug={SLUG} title={META_TITLE} />
          <Heading as="h1">Turbolaaduri eluiga pikendavad hooldused – mida vanematel autodel arvestada?</Heading>

          <p>
            Turbolaadur on üks kallimaid ja samal ajal kõige haavatavamaid komponente vanemal autol. Hea uudis –
            <strong>turbo eluiga</strong> sõltub suuresti hooldusest ja sõiduvõtetest, mitte ainult läbisõidust.
          </p>

          <Heading as="h2">Õli – turbolaaduri elu ja surm</Heading>
          <p>
            Turbo võll pöörleb kuni 200–250 tuhat pööret minutis. See tähendab, et <strong>õlikvaliteet ja õlivahetusintervall</strong>{" "}
            on kriitilised. Vana õli koksistub kuumal turbo korpusel, ummistab õlituskanalid ja lõpptulemus on täielik rike.
          </p>

          <Heading as="h2">Miks õlivahetus peab olema tihedam kui „tehase 30 000 km“?</Heading>
          <p>
            Vanematel turbomootoritel on rohkem blow-by’d, tahma ja kütusejääke, mis sattuvad õlisse. Seetõttu on soovitatav{" "}
            <strong>lühendada õlivahetusintervalli</strong> (nt 10–15k km või kord aastas), isegi kui tehas lubas paberil rohkem.
          </p>

          <Heading as="h2">Külma ja kuuma turbo reegel</Heading>
          <p>Kaks lihtsat mängureeglit:</p>
          <ul>
            <li>Ära „pane põhja“ kohe pärast külmkäivitust – õli peab jõudma turboni.</li>
            <li>Ära lülita mootorit kohe välja pärast tugevat koormust – lase 30–60 sekundit rahulikult tühikäigul jahtuda.</li>
          </ul>
          <p>See vähendab drastiliselt <strong>turbo ülekuumenemist ja koksistumist</strong>.</p>

          <Heading as="h2">Õlilekked turbos – mida jälgida?</Heading>
          <p>
            Sinine suits kiirendusel või pärast pikemat seismist võib viidata <strong>turbo võllitihendite lekkimisele</strong>.
            Lisaks tasub kontrollida, kas intercooleris ja sisselaskesüsteemis on ebatavaliselt palju õlijälgi.
          </p>

          <Heading as="h2">Rõhu ja vaakumi kontroll</Heading>
          <p>
            Vanematel autodel väsivad <strong>geomeetria mehhanismid, vaakumvoolikud ja rõhuandurid</strong>. Kui turbo ei puhu
            piisavalt või lööb üle, kannatavad nii jõudlus kui ka komponentide eluiga. Regulaarsel hooldusel tasub lasta kontrollida
            reaalset ülerõhku, mitte eeldada, et kõik on korras.
          </p>

          <Heading as="h2">Õige õli + õige jahutus = pikaealine turbo</Heading>
          <p>
            Kombinatsioon <strong>kvaliteetsest mootoriõlist, tihedast õlivahetusest, toimivast jahutussüsteemist ja mõistlikest
            sõiduvõtetest</strong> pikendab turbolaaduri eluiga kordades. Vanal autol ei ole turbo tarbekaup, vaid strateegiline
            komponent, mida tasub hoida.
          </p>
        </article>
      </main>
    </div>
  );
}

