import React from "react";
import { useArticleMeta } from "../../src/lib/useArticleMeta";
import { articleBaseStyles, articleContainerStyles, articleHeadingStyles } from "../../src/lib/articleStyles";
import { BlogHero } from "../../src/lib/blogHero";

const SLUG = "rehvid-ja-vanem-auto";
const META_TITLE = "Rehvid ja vanem auto – kuidas vale rõhk tapab veermiku?";
const META_DESCRIPTION =
  "Analüüsime, kuidas vale rehvirõhk ja tüüpilised vead vanemal autol kulutavad veermiku, tõstavad kütusekulu ja vähendavad ohutust.";

const META_TAGS = [
  { name: "description", content: META_DESCRIPTION },
  { property: "og:type", content: "article" },
  { property: "og:title", content: META_TITLE },
  { property: "og:description", content: META_DESCRIPTION },
  { property: "og:url", content: `https://sinu-domeen.ee/blogi/${SLUG}` },
];

const STRUCTURED_DATA = {
  "@context": "https://schema.org",
  "@type": "BlogPosting",
  headline: META_TITLE,
  description: META_DESCRIPTION,
  author: { "@type": "Person", name: "LEISSON" },
  genre: "Automotive",
  keywords: "rehvirõhk, veermiku hooldus, rehvide kulumine",
  articleSection: "Autohooldus",
  mainEntityOfPage: {
    "@type": "WebPage",
    "@id": `https://sinu-domeen.ee/blogi/${SLUG}`,
  },
};

const Heading = ({ as: Tag, children }) => (
  <Tag style={Tag === "h1" ? articleHeadingStyles.h1 : articleHeadingStyles.h2}>{children}</Tag>
);

export default function BlogRehvidJaVanemAuto() {
  useArticleMeta({
    title: META_TITLE,
    description: META_DESCRIPTION,
    metaTags: META_TAGS,
    structuredData: STRUCTURED_DATA,
    schemaId: "schema-rehvid-ja-vanem-auto",
  });

  return (
    <div style={articleBaseStyles}>
      <main style={articleContainerStyles}>
        <article>
          <BlogHero slug={SLUG} title={META_TITLE} />
          <Heading as="h1">Rehvid ja vanem auto – kuidas vale rõhk ja tüüpilised vead tapavad veermiku?</Heading>

          <p>
            Rehvid ei ole ainult „mustad rõngad“, mis autot edasi veavad. Vanema auto puhul mõjutavad <strong>rehvirõhk ja rehvide seisukord</strong>
            otseselt veermiku, roolisüsteemi ja vedrustuse eluiga. Valed otsused siin tähendavad kiiremini kuluvat silda ja suuremaid remondiarveid.
          </p>

          <Heading as="h2">Liiga madal rehvirõhk = tappev koormus veermikule</Heading>
          <p>
            Madala rõhuga rehv deformeerub rohkem, soojeneb üle ja koormab vedrustust. Iga löökaugust läbi sõidetud löök kandub edasi <strong>puksidele, amortidele,
            šarniiridele ja rooliotstele</strong>. Vanem auto ei andesta – nõrgad kohad annavad kiiresti järele.
          </p>

          <Heading as="h2">Ülerõhk – “jäik” sõit ja mikrolöögid sillale</Heading>
          <p>
            Liiga kõva rehv tundub esmapilgul „terav ja konkreetne“, aga tegelikult kandub iga tee ebatasasus otse <strong>silla- ja keredetailidele</strong>.
            See tähendab kiiremat kulumist puksidele ja kinnitustele ning rohkem müra salongis.
          </p>

          <Heading as="h2">Ebaühtlane rehvikulumine annab märku silla- või rõhu probleemist</Heading>
          <p>
            Kui rehv on seest või väljast servast rohkem kulunud, on mängus kas vale rõhk, vale sillanurk või mõlemad. <strong>Feathering, saagimine ja „kantis“ muster</strong>
            on selged signaalid, et veermik ja sillastend vajavad ülevaatust.
          </p>

          <Heading as="h2">Valesti valitud rehv suurendab veermiku koormust</Heading>
          <p>
            Väga odavad või autole mitte sobiva mõõduga rehvid võivad muuta auto käitumist nii, et <strong>vedrustus töötab pidevalt piiri peal</strong>.
            Liiga kõrge külgseina või vale koormusindeksiga rehv ei toeta veermiku tööd, vaid tekitab lisalõtkeid ja vibratsiooni.
          </p>

          <Heading as="h2">Balansseerimata rattad = püsiv vibratsioon sillale</Heading>
          <p>
            Rooli või kere vibratsioon kindlatel kiirustel viitab <strong>balansseerimata ratastele</strong>. Kui seda ignoreerida, saavad lisakoormuse
            rattalaagrid, roolivarras, roolilatt ja amordid. Vanem sild annab sellisele kohtlemisele kiiresti vastulöögi.
          </p>

          <Heading as="h2">Vale hooajarehv vales kliimas</Heading>
          <p>
            Suverehv talvel või „pool-lamell“ aastaringi Eestimaa teedel tähendab kehvemat haardumist ja rohkem libisemist. Iga kord, kui <strong>ABS või veojõukontroll pidevalt sekkub</strong>,
            on see signaal, et rehv ei tee oma tööd – ja veermik peab rohkem „tõmblema“.
          </p>

          <Heading as="h2">Kokkuvõte: rehvid on veermiku esimene kaitseliin</Heading>
          <p>
            <strong>Vanema auto veermiku eluiga</strong> sõltub suuresti sellest, mis seisus on rehvid ja milline on rehvirõhk. Õige rõhk, kvaliteetne rehv ja korrektne sillastend
            hoiavad kolinad, lõtkud ja enneaegse kulumise kontrolli all.
          </p>
        </article>
      </main>
    </div>
  );
}
