import React from "react";
import { useArticleMeta } from "../../src/lib/useArticleMeta";
import { articleBaseStyles, articleContainerStyles, articleHeadingStyles } from "../../src/lib/articleStyles";
import { BlogHero } from "../../src/lib/blogHero";

const SLUG = "kaigukasti-oli-lifetime";
const META_TITLE = "Käigukasti õli “lifetime”: kas tootja lubadus või ilus müügijutt?";
const META_DESCRIPTION =
  "Lahti seletus, mida tähendab käigukasti õli “lifetime fill”, miks automaat- ja manuaalkast vajavad regulaarset hooldust ning mis juhtub, kui õli ei vaheta.";

const META_TAGS = [
  { name: "description", content: META_DESCRIPTION },
  { property: "og:type", content: "article" },
  { property: "og:title", content: META_TITLE },
  { property: "og:description", content: META_DESCRIPTION },
  { property: "og:url", content: `https://sinu-domeen.ee/blogi/${SLUG}` },
];

const STRUCTURED_DATA = {
  "@context": "https://schema.org",
  "@type": "BlogPosting",
  headline: META_TITLE,
  description: META_DESCRIPTION,
  author: { "@type": "Person", name: "LEISSON" },
  genre: "Automotive",
  keywords: "käigukasti õli, automaatkäigukast, lifetime fill",
  articleSection: "Autohooldus",
  mainEntityOfPage: {
    "@type": "WebPage",
    "@id": `https://sinu-domeen.ee/blogi/${SLUG}`,
  },
};

const Heading = ({ as: Tag, children }) => (
  <Tag style={Tag === "h1" ? articleHeadingStyles.h1 : articleHeadingStyles.h2}>{children}</Tag>
);

const Section = ({ title, children, as = "h2" }) => (
  <section>
    <Heading as={as}>{title}</Heading>
    {children}
  </section>
);

export default function BlogKaigukastiOliLifetime() {
  useArticleMeta({
    title: META_TITLE,
    description: META_DESCRIPTION,
    metaTags: META_TAGS,
    structuredData: STRUCTURED_DATA,
    schemaId: "schema-kaigukasti-oli-lifetime",
  });

  return (
    <div style={articleBaseStyles}>
      <main style={articleContainerStyles}>
        <article>
          <BlogHero slug={SLUG} title={META_TITLE} />
          <header>
            <Heading as="h1">Käigukasti õli “lifetime”: kas tootja lubadus või ilus müügijutt?</Heading>
            <Section title="Alternatiivsed pealkirjad" as="h2">
              <ul>
                <li>Käigukasti õli “eluea täitmine”: mida see tegelikult tähendab?</li>
                <li>Automaatkäigukasti õli: miks “lifetime” ei tähenda auto elu lõpuni?</li>
                <li>Manuaalkasti ja automaatkasti õlivahetus – kas tootja soovitus on piisav?</li>
              </ul>
            </Section>
            <p>
              Tootja “lifetime fill” kõlab turunduslikult kenasti, aga reaalsuses tähendab see enamasti “kuni garantiiperioodi lõpuni”. Käigukasti õli töötab ekstreemse koormuse all – eriti automaatkastides, kus hüdraulika, siduripakid ja temperatuur kõigi piirideni pingutavad. Kui õli ei vahetata, hakkavad esimesena märku andma libisemine, jõnksud ja kuumaga tekkivad vead.
            </p>
          </header>

          <Section title="Mida “lifetime” käigukasti õli puhul päriselt tähendab?">
            <p>
              Enamiku tootjate jaoks on <strong>“lifetime” sisuliselt garantiiperioodi pikkune eluiga</strong> – mitte sinu auto reaalne tehniline elutsükkel. Pärast 150–200 tuhande kilomeetri piiri on õli lisandid väsinud, viskoossus langenud ja metalliosakesed ringluses.
            </p>
            <p>
              Eriti karm on pilt automaatkäigukastides, kus õli vastutab samaaegselt nii <strong>määretöö, jahutuse kui hüdraulika</strong> eest. Kui see üks ja sama vedelik on väsinud, kannatab kogu süsteem.
            </p>
          </Section>

          <Section title="Mis juhtub, kui käigukasti õli ei vaheta?">
            <ul>
              <li>
                <strong>Libisemine ja veniv käiguvahetus:</strong> siduripakid kaotavad haarduvuse, kast “ujub” ja käigud ei lukustu enam puhtalt.
              </li>
              <li>
                <strong>Jõnksud ja löögid käiguvahetusel:</strong> määrdunud õli põhjustab hüdroploki klappide hangumist, tekivad löögid ja ebamugav käitumine.
              </li>
              <li>
                <strong>Temperatuuriprobleemid:</strong> ülekuumenenud õli kaotab omadused, tihendid kõvastuvad ja hakkavad lekkima, kuumaga ilmnevad vead kiiremini.
              </li>
              <li>
                <strong>Manuaalkastis – laagrid ja sünkrod:</strong> vananenud õli ei kaitse enam hammasrattaid ja laagreid, metall-metall kontakt kiirendab kulumist.
              </li>
            </ul>
          </Section>

          <Section title="Soovituslikud intervallid: automaat vs manuaal">
            <p>
              Praktikas tasub automaatkäigukasti õli vahetada keskmiselt iga <strong>60 000–80 000 km</strong> järel ning manuaalkastis iga <strong>80 000–120 000 km</strong> järel. Kui kast juba jõnksutab või kuumaga “veidralt” käitub, tähendab see, et oled hoolduses hiljaks jäänud.
            </p>
            <p>
              Õigeaegne õlivahetus on oluliselt odavam kui hüdroploki remont või käigukasti kapitaalremont. Ennetav hooldus on siin puhas riskijuhtimine, mitte “soovituslik lisateenus”.
            </p>
          </Section>

          <section>
            <Heading as="h2">Soovid käigukasti õli vahetust teha targalt, mitte viimasel hetkel?</Heading>
            <p>
              <a href="/kontakt">Võta Nisbeliga ühendust</a> ja teeme sinu automaat- või manuaalkastile sihitud hooldusplaani: õli vahetus, filtri vahetus, vajadusel ka käigukasti diagnostika. Ära oota, kuni kast juba libiseb ja jõnksutab – tegutse enne, kui kahju tekib.
            </p>
          </section>
        </article>
      </main>
    </div>
  );
}
